import{_ as i,a,b as n}from"./chunks/管理端登录界面.yuERlcJ6.js";import{_ as t,o,c as s,a2 as l}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Authentication او Login Device Management","description":"","frontmatter":{},"headers":[],"relativePath":"ps/Safety/authentication-and-login-devices.md","filePath":"ps/Safety/authentication-and-login-devices.md","lastUpdated":1781962217000}'),d={name:"ps/Safety/authentication-and-login-devices.md"};function c(r,e,p,u,m,h){return o(),s("div",null,[...e[0]||(e[0]=[l('<h1 id="authentication-او-login-device-management" tabindex="-1">Authentication او Login Device Management <a class="header-anchor" href="#authentication-او-login-device-management" aria-label="Permalink to &quot;Authentication او Login Device Management&quot;">​</a></h1><p><code>Authentication Management</code> او <code>Login Device Management</code> ستاسو د ImgBed admin panel، public upload entry او WebDAV access ساتنه کوي.</p><p>دا پاڼه د access credentials ټاکلو، signed-in devices کتلو او د اړتیا پر وخت د زړو sessions revoke کولو لپاره وکاروئ.</p><h2 id="چېرته-یې-تنظیم-کړئ" tabindex="-1">چېرته یې تنظیم کړئ <a class="header-anchor" href="#چېرته-یې-تنظیم-کړئ" aria-label="Permalink to &quot;چېرته یې تنظیم کړئ&quot;">​</a></h2><p>admin panel پرانیزئ، بیا دې ځای ته لاړ شئ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings</span></span></code></pre></div><p>پاڼه دوه اصلي برخې لري:</p><ul><li>Authentication Management</li><li>Login Device Management</li></ul><p><img src="'+i+'" alt="Authentication management" loading="lazy"></p><h2 id="authentication-management-څه-کوي" tabindex="-1">Authentication Management څه کوي <a class="header-anchor" href="#authentication-management-څه-کوي" aria-label="Permalink to &quot;Authentication Management څه کوي&quot;">​</a></h2><p>Authentication Management د access credentials ساتي.</p><p>دوه ډولونه لري:</p><ul><li>User-side authentication</li><li>Admin-side authentication</li></ul><h2 id="user-side-authentication" tabindex="-1">User-Side Authentication <a class="header-anchor" href="#user-side-authentication" aria-label="Permalink to &quot;User-Side Authentication&quot;">​</a></h2><p>User-side authentication د upload password دی.</p><p>کله چې upload password وټاکل شي، عادي visitors باید د upload page له کارولو مخکې دا password ولیکي. دا هغه وخت ګټور دی چې نه غواړئ public upload page هر چا ته پرانیستی وي.</p><p><img src="'+a+'" alt="User login page" loading="lazy"></p><h3 id="د-upload-password-ټاکل" tabindex="-1">د Upload Password ټاکل <a class="header-anchor" href="#د-upload-password-ټاکل" aria-label="Permalink to &quot;د Upload Password ټاکل&quot;">​</a></h3><p>کله چې upload password تنظیم وي:</p><ul><li>visitors باید د upload page له کارولو مخکې password ولیکي.</li><li>upload یوازې هغه وخت فعالېږي چې password ومنل شي.</li><li>که user-side device sessions فعال وي، ImgBed هغه user-side device ثبتوي.</li></ul><p>د upload password بدلول زاړه user-side sessions باطلوي. visitors باید نوی password بیا ولیکي.</p><h2 id="admin-side-authentication" tabindex="-1">Admin-Side Authentication <a class="header-anchor" href="#admin-side-authentication" aria-label="Permalink to &quot;Admin-Side Authentication&quot;">​</a></h2><p>Admin-side authentication د admin username او password کاروي.</p><p>دا admin panel ساتي. د production کارونې لپاره یې تل تنظیمول پکار دي.</p><p><img src="'+n+'" alt="Admin login page" loading="lazy"></p><h3 id="د-admin-credentials-ټاکل" tabindex="-1">د Admin Credentials ټاکل <a class="header-anchor" href="#د-admin-credentials-ټاکل" aria-label="Permalink to &quot;د Admin Credentials ټاکل&quot;">​</a></h3><p>کله چې admin username او password تنظیم وي:</p><ul><li>admin panel پرانیستل login غواړي.</li><li>بریالی login د admin device record جوړوي.</li><li>په Login Device Management کې devices کتل، پاکول یا force offline کولای شئ.</li></ul><p>د admin username یا password بدلول زاړه admin sessions باطلوي. بیا sign in ته اړتیا لرئ.</p><h2 id="login-device-management-څه-کوي" tabindex="-1">Login Device Management څه کوي <a class="header-anchor" href="#login-device-management-څه-کوي" aria-label="Permalink to &quot;Login Device Management څه کوي&quot;">​</a></h2><p>Login Device Management هغه devices ښيي چې sign in شوي وي.</p><p>دا درسره مرسته کوي وګورئ:</p><ul><li>کوم devices admin panel ته داخل شوي دي.</li><li>کوم devices user-side upload page ته داخل شوي دي.</li><li>کوم WebDAV clients نښلول شوي دي.</li><li>device session لا valid دی که نه.</li><li>زاړه devices باید force offline شي که نه.</li></ul><p>پاڼه درې tabs لري:</p><ul><li>Admin</li><li>User</li><li>WebDAV</li></ul><h2 id="global-cookie-security" tabindex="-1">Global Cookie Security <a class="header-anchor" href="#global-cookie-security" aria-label="Permalink to &quot;Global Cookie Security&quot;">​</a></h2><p>د Login Device Management په سر کې global cookie behavior تنظیمولای شئ.</p><h3 id="user-cookie-lifetime" tabindex="-1">User Cookie Lifetime <a class="header-anchor" href="#user-cookie-lifetime" aria-label="Permalink to &quot;User Cookie Lifetime&quot;">​</a></h3><p>کنټرولوي چې user-side login څو ورځې active پاتې شي.</p><p>د بېلګې په توګه، که یې 14 days ته وټاکئ، visitors عموما په 14 ورځو کې upload password بیا نه لیکي.</p><h3 id="admin-cookie-lifetime" tabindex="-1">Admin Cookie Lifetime <a class="header-anchor" href="#admin-cookie-lifetime" aria-label="Permalink to &quot;Admin Cookie Lifetime&quot;">​</a></h3><p>کنټرولوي چې admin login څو ورځې active پاتې شي.</p><p>د بېلګې په توګه، که یې 14 days ته وټاکئ، administrators عموما په 14 ورځو کې بیا sign in ته اړتیا نه لري.</p><h3 id="secure-mode" tabindex="-1">Secure Mode <a class="header-anchor" href="#secure-mode" aria-label="Permalink to &quot;Secure Mode&quot;">​</a></h3><p>کله چې Secure mode فعال وي، browsers login cookies یوازې د HTTPS له لارې لېږي.</p><p>د production HTTPS sites لپاره یې فعال کړئ. د local HTTP testing لپاره یې مه فعالوئ، که نه ممکن داسې حالت ووینئ چې &quot;login بریالی شو، خو refresh وروسته مې وباسي&quot;.</p><h2 id="admin-login-devices" tabindex="-1">Admin Login Devices <a class="header-anchor" href="#admin-login-devices" aria-label="Permalink to &quot;Admin Login Devices&quot;">​</a></h2><p>Admin tab هغه devices ښيي چې admin panel ته sign in شوي وي.</p><p>Device records یوازې هغه وخت ښکاري چې admin credentials تنظیم وي او admin panel د login له لارې پرانیستل شوی وي.</p><p>هر device card دا معلومات ښودلای شي:</p><ul><li>Device او browser معلومات</li><li>First login IP</li><li>Last active IP</li><li>Login time</li><li>Last active time</li><li>Expiration time</li><li>Current status</li></ul><p>که ناپېژندل شوی device ووینئ، <code>Force Offline</code> وکاروئ څو session یې invalid شي.</p><h2 id="زاړه-devices-پاکول" tabindex="-1">زاړه Devices پاکول <a class="header-anchor" href="#زاړه-devices-پاکول" aria-label="Permalink to &quot;زاړه Devices پاکول&quot;">​</a></h2><p><code>Clean Up Old Devices</code> په اوسني tab کې زاړه login records په bulk ډول لرې کوي.</p><p>دا هغه وخت وکاروئ چې شک لرئ زاړه sessions ښايي لا هم پر نورو devices active وي.</p><h2 id="force-offline" tabindex="-1">Force Offline <a class="header-anchor" href="#force-offline" aria-label="Permalink to &quot;Force Offline&quot;">​</a></h2><p><code>Force Offline</code> د یوه device session invalid کوي.</p><p>کله چې device force offline شي:</p><ul><li>Admin devices باید بیا sign in وکړي.</li><li>User-side devices باید upload password بیا ولیکي.</li><li>WebDAV clients باید بیا authenticate شي.</li></ul><p>Expired یا invalid devices هم لرې کېدای شي.</p><h2 id="له-اوسني-device-څخه-sign-out" tabindex="-1">له اوسني Device څخه Sign Out <a class="header-anchor" href="#له-اوسني-device-څخه-sign-out" aria-label="Permalink to &quot;له اوسني Device څخه Sign Out&quot;">​</a></h2><p>اوسنی device card د <code>Current Device</code> په نوم نښه شوی وي.</p><p>له اوسني device څخه تر sign out وروسته:</p><ul><li>اوسنی admin session sign out کېږي.</li><li>اوسنی user-side session sign out کېږي.</li></ul><p>د هغې برخې د دوامدارې کارونې لپاره باید بیا sign in وکړئ.</p>',65)])])}const b=t(d,[["render",c]]);export{f as __pageData,b as default};
